38	impl TrayHandle {
39	    /// Spawn the tray on a dedicated tokio thread. Returns immediately.
40	    /// Returns `None` if the D-Bus session bus is not available (e.g. headless CI).
41	    pub fn spawn() -> Option<Self> {
42	        let open_window = Arc::new(AtomicBool::new(false));
43	        let open_window_clone = Arc::clone(&open_window);
44	
45	        let (tx, rx) = std::sync::mpsc::channel::<Result<(), String>>();
46	
47	        let thread = std::thread::Builder::new()
48	            .name("tray-tokio".into())
49	            .spawn(move || {
50	                let rt = match tokio::runtime::Builder::new_current_thread()
51	                    .enable_all()
52	                    .build()
53	                {
54	                    Ok(rt) => rt,
55	                    Err(e) => {
56	                        let _ = tx.send(Err(format!("tokio runtime build failed: {e}")));
57	                        return;
58	                    }
59	                };
60	
61	                rt.block_on(async move {
62	                    let tray = VibeTray {
63	                        open_window: Arc::clone(&open_window_clone),
64	                        state: Arc::new(Mutex::new(TrayState::default())),
65	                    };
66	                    let state_ref = Arc::clone(&tray.state);
67	
68	                    match tray.spawn().await {
69	                        Ok(handle) => {
70	                            let _ = tx.send(Ok(()));
71	
72	                            // Spawn the poll loop inside the same tokio runtime.
73	                            let poll_handle = handle.clone();
74	                            tokio::spawn(async move {
75	                                loop {
76	                                    tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;
77	
78	                                    let status = query_status();
79	                                    let new_daemon_state = status.as_ref().map(|s| s.state.clone());
80	                                    let new_active_profile = status.and_then(|s| s.active_profile);
81	                                    // Read profile list from disk on each tick — cheap stat, no daemon needed.
82	                                    let new_profiles = load_profiles();
83	
84	                                    // Only push a D-Bus update when the visible state actually changed.
85	                                    let changed = {
86	                                        let s = state_ref.lock().await;
87	                                        s.daemon_state != new_daemon_state
88	                                            || s.active_profile != new_active_profile
89	                                            || s.profiles != new_profiles
90	                                    };
91	
92	                                    if changed {
93	                                        poll_handle
94	                                            .update(|tray: &mut VibeTray| {
95	                                                if let Ok(mut s) = tray.state.try_lock() {
96	                                                    s.daemon_state = new_daemon_state.clone();
97	                                                    s.active_profile = new_active_profile.clone();
98	                                                    s.profiles = new_profiles.clone();
99	                                                }
100	                                            })
101	                                            .await;
102	                                    }
103	                                }
104	                            });
105	
106	                            std::future::pending::<()>().await;
107	                        }
108	                        Err(e) => {
109	                            let _ = tx.send(Err(format!("tray spawn failed: {e}")));
110	                        }
111	                    }
112	                });
113	            })
114	            .ok()?;
115	
116	        match rx.recv() {
117	            Ok(Ok(())) => Some(TrayHandle {
118	                open_window,
119	                _thread: thread,
120	            }),
121	            Ok(Err(e)) => {
122	                tracing::warn!(reason = %e, "System tray unavailable");
123	                None
124	            }
125	            Err(_) => None,
126	        }
127	    }
128	
129	    /// Returns true (and resets the flag) if the tray requested the window to open.
130	    pub fn take_open_request(&self) -> bool {
131	        self.open_window.swap(false, Ordering::AcqRel)
132	    }
133	}
