170	            None => "Not running".into(),
171	            Some(DaemonState::Idle) => "Idle — listening for wake word".into(),
172	            Some(DaemonState::Muted) => "Muted".into(),
173	            Some(DaemonState::Listening) => "Listening…".into(),
