183	    fn menu(&self) -> Vec<MenuItem<Self>> {
184	        let state = self.current_state();
185	        let is_muted = matches!(state.daemon_state, Some(DaemonState::Muted));
186	        let daemon_running = state.daemon_state.is_some();
187	
188	        let open_flag = Arc::clone(&self.open_window);
189	
190	        let mut items: Vec<MenuItem<Self>> = Vec::new();
191	
192	        items.push(
193	            StandardItem {
194	                label: "Open Config".into(),
195	                icon_name: "preferences-system".into(),
196	                activate: Box::new(move |_this: &mut Self| {
197	                    open_flag.store(true, Ordering::Release);
198	                }),
199	                ..Default::default()
200	            }
201	            .into(),
202	        );
203	
204	        items.push(MenuItem::Separator);
205	
206	        if daemon_running {
207	            let mute_label = if is_muted { "Unmute" } else { "Mute" };
208	            let mute_icon = if is_muted {
209	                "audio-input-microphone"
210	            } else {
211	                "audio-input-microphone-muted"
212	            };
213	            items.push(
214	                StandardItem {
215	                    label: mute_label.into(),
216	                    icon_name: mute_icon.into(),
217	                    activate: Box::new(move |_this: &mut Self| {
218	                        let cmd = if is_muted {
219	                            ControlRequest::Unmute
220	                        } else {
221	                            ControlRequest::Mute
222	                        };
223	                        // Fire-and-forget on a fresh thread — ksni callbacks must not block.
224	                        std::thread::spawn(move || {
225	                            let _ = send_command(cmd);
226	                        });
227	                    }),
228	                    ..Default::default()
229	                }
230	                .into(),
231	            );
232	            items.push(MenuItem::Separator);
233	        }
234	
235	        // Profile switcher submenu — always shown, disabled when daemon is not running.
236	        let profile_submenu: Vec<MenuItem<Self>> = state
237	            .profiles
238	            .iter()
239	            .map(|name| {
240	                let is_active = state.active_profile.as_deref() == Some(name.as_str());
241	                let name_clone = name.clone();
242	                CheckmarkItem {
243	                    label: name.clone(),
244	                    checked: is_active,
245	                    enabled: daemon_running,
246	                    activate: Box::new(move |_this: &mut Self| {
247	                        let req = ControlRequest::SwitchProfile {
248	                            name: name_clone.clone(),
249	                        };
250	                        std::thread::spawn(move || {
251	                            let _ = send_command(req);
252	                        });
253	                    }),
254	                    ..Default::default()
255	                }
256	                .into()
257	            })
258	            .collect();
259	
260	        items.push(
261	            SubMenu {
262	                label: "Profiles".into(),
263	                icon_name: "folder".into(),
264	                enabled: !state.profiles.is_empty(),
265	                submenu: profile_submenu,
266	                ..Default::default()
267	            }
268	            .into(),
269	        );
270	
271	        items.push(MenuItem::Separator);
272	
273	        items.push(
274	            StandardItem {
275	                label: "Quit".into(),
276	                icon_name: "application-exit".into(),
277	                activate: Box::new(|_| std::process::exit(0)),
278	                ..Default::default()
279	            }
280	            .into(),
281	        );
282	
283	        items
284	    }
285	}
